int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long A,B,C,D; scanf("%lld %lld %lld %lld", &A, &B, &C, &D);
        // first gift
        if(B > A){ // Sobhagya winning, Nitin is loser
            A += C;
        } else { // Nitin winning, Sobhagya is loser
            B += C;
        }
        // second gift
        if(B > A){
            A += D;
        } else {
            B += D;
        }
        if(B > A) printf("S\n"); else printf("N\n");
    }
    return 0;
}

