#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        A = int(next(it)); B = int(next(it)); C = int(next(it)); D = int(next(it))
        if B > A:
            A += C
        else:
            B += C
        if B > A:
            A += D
        else:
            B += D
        out.append('S' if B > A else 'N')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

